package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testParse_withValidReader_returnsCSVParser() throws IOException {
        Reader mockReader = mock(Reader.class);
        CSVParser parser = csvFormat.parse(mockReader);
        assertNotNull(parser);
        assertEquals(mockReader, parser.getReader());
        assertEquals(csvFormat, parser.getFormat());
    }

    @Test
    void testParse_withNullReader_throwsNullPointerException() {
        assertThrows(NullPointerException.class, () -> csvFormat.parse(null));
    }

    @Test
    void testParse_multipleCalls_returnDifferentInstances() throws IOException {
        Reader mockReader1 = mock(Reader.class);
        Reader mockReader2 = mock(Reader.class);

        CSVParser parser1 = csvFormat.parse(mockReader1);
        CSVParser parser2 = csvFormat.parse(mockReader2);

        assertNotSame(parser1, parser2);
        assertEquals(mockReader1, parser1.getReader());
        assertEquals(mockReader2, parser2.getReader());
    }
}
